import java.util.*;
public class MyLinkedList {
    private static class Node{int val;Node next;Node(int v){val=v;}}
    private Node head;
    public void addHead(int val){Node n=new Node(val);n.next=head;head=n;}
    public void addTail(int val){
        if(head==null){head=new Node(val);return;}
        Node c=head; while(c.next!=null)c=c.next; c.next=new Node(val);
    }
    public boolean delete(int val){
        Node dummy=new Node(0);dummy.next=head;Node prev=dummy,c=head;
        while(c!=null){if(c.val==val){prev.next=c.next;head=dummy.next;return true;}
        prev=c;c=c.next;} return false;
    }
    public boolean contains(int val){Node c=head;while(c!=null){if(c.val==val)return true;c=c.next;}return false;}
    public int[] toArray(){
        List<Integer> l=new ArrayList<>();Node c=head;while(c!=null){l.add(c.val);c=c.next;}
        return l.stream().mapToInt(Integer::intValue).toArray();
    }
    public static void main(String[] args){
        MyLinkedList list=new MyLinkedList();
        list.addHead(3);list.addHead(1);list.addTail(5);
        System.out.println(Arrays.toString(list.toArray()));
        list.delete(3);
        System.out.println(Arrays.toString(list.toArray()));
        System.out.println(list.contains(5));
        System.out.println("O(1) addHead, O(n) addTail/delete/contains");
    }
}

