public class RemoveNthFromEnd {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode removeNthFromEnd(ListNode head, int n) {
        ListNode dummy=new ListNode(0);dummy.next=head;
        ListNode fast=dummy,slow=dummy;
        for(int i=0;i<=n;i++) fast=fast.next; // advance fast n+1 steps
        while(fast!=null){fast=fast.next;slow=slow.next;}
        slow.next=slow.next.next; // skip the nth from end
        return dummy.next;
    }
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
