public class IntersectionLL {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    public static ListNode getIntersectionNode(ListNode headA, ListNode headB) {
        // Two pointers: when one reaches end, redirect to other list's head
        // After at most len(A)+len(B) steps, they meet at intersection (or both null)
        ListNode a=headA, b=headB;
        while(a!=b){
            a=(a==null)?headB:a.next;
            b=(b==null)?headA:b.next;
        }
        return a; // intersection node or null
    }
    public static void main(String[] args){
        ListNode shared=new ListNode(8);shared.next=new ListNode(4);shared.next.next=new ListNode(5);
        ListNode a=new ListNode(4);a.next=new ListNode(1);a.next.next=shared;
        ListNode b=new ListNode(5);b.next=new ListNode(6);b.next.next=new ListNode(1);b.next.next.next=shared;
        System.out.println(getIntersectionNode(a,b).val); // 8
        System.out.println("O(n+m) time, O(1) space — two pointer redirect");
        System.out.println("Key: both pointers travel same total distance (n+m)");
    }
}

