public class FlattenMultilevel {
    static class Node{int val;Node prev,next,child;
        Node(int v){val=v;}}
    public static Node flatten(Node head) {
        if(head==null) return null;
        Node curr=head;
        while(curr!=null){
            if(curr.child!=null){
                Node child=curr.child;
                Node next=curr.next;
                // Connect curr→child:
                curr.next=child;child.prev=curr;curr.child=null;
                // Find tail of child list:
                Node tail=child;
                while(tail.next!=null) tail=tail.next;
                // Connect tail→next:
                tail.next=next;
                if(next!=null) next.prev=tail;
            }
            curr=curr.next;
        }
        return head;
    }
    static String str(Node h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] args){
        Node n1=new Node(1),n2=new Node(2),n3=new Node(3);
        n1.next=n2;n2.prev=n1;n2.next=n3;n3.prev=n2;
        Node c1=new Node(7),c2=new Node(8);
        c1.next=c2;c2.prev=c1;
        n2.child=c1;
        System.out.println(str(flatten(n1))); // 1-2-7-8-3
        System.out.println("O(n) — each node visited at most twice");
    }
}

