import java.util.*;
public class CopyRandomList {
    static class Node{int val;Node next,random;Node(int v){val=v;}}
    public static Node copyRandomList(Node head) {
        if(head==null) return null;
        // Step 1: interleave — original→copy→original.next
        Node curr=head;
        while(curr!=null){
            Node copy=new Node(curr.val);
            copy.next=curr.next;
            curr.next=copy;
            curr=copy.next;
        }
        // Step 2: set random pointers for copies
        curr=head;
        while(curr!=null){
            if(curr.random!=null)
                curr.next.random=curr.random.next;
            curr=curr.next.next;
        }
        // Step 3: separate the two lists
        Node dummy=new Node(0),copyCurr=dummy;
        curr=head;
        while(curr!=null){
            copyCurr.next=curr.next;
            curr.next=curr.next.next;
            copyCurr=copyCurr.next;
            curr=curr.next;
        }
        return dummy.next;
    }
    public static void main(String[] args){
        Node n1=new Node(7),n2=new Node(13),n3=new Node(11);
        n1.next=n2;n2.next=n3;
        n1.random=null;n2.random=n1;n3.random=n3;
        Node copy=copyRandomList(n1);
        System.out.println(copy.val+" "+copy.next.val+" "+copy.next.next.val); // 7 13 11
        System.out.println(copy.next.random==copy);            // true
        System.out.println(copy.next.next.random==copy.next.next); // true
        System.out.println("O(n) time, O(1) extra space — 3-step interleave");
    }
}

