    private static class Node{int val;Node next;Node(int v){val=v;}}
    private Node dummy=new Node(0); // dummy head
    private int size=0;
    public int get(int i){
        if(i<0||i>=size) return -1;
        Node c=dummy.next; for(int k=0;k<i;k++) c=c.next; return c.val;
    }
    public void addAtHead(int v){ addAtIndex(0,v); }
    public void addAtTail(int v){ addAtIndex(size,v); }
    public void addAtIndex(int i,int v){
        if(i<0||i>size) return;
        Node prev=dummy; for(int k=0;k<i;k++) prev=prev.next;
        Node n=new Node(v);n.next=prev.next;prev.next=n;size++;
    }
    public void deleteAtIndex(int i){
        if(i<0||i>=size) return;
        Node prev=dummy; for(int k=0;k<i;k++) prev=prev.next;
        prev.next=prev.next.next;size--;
    }
    public static void main(String[] args){
        DesignLinkedList list=new DesignLinkedList();
        list.addAtHead(1);list.addAtTail(3);list.addAtIndex(1,2);
        System.out.println(list.get(1)); // 2
        list.deleteAtIndex(1);
        System.out.println(list.get(1)); // 3
        System.out.println("Design LL with dummy head — all ops use same pointer pattern");
    }
}

