import java.util.Arrays;
public class LLBasicsSynthesis {
    static class ListNode{int val;ListNode next;ListNode(int v){val=v;}}
    static ListNode removeNthFromEnd(ListNode head,int n){
        ListNode d=new ListNode(0);d.next=head;ListNode f=d,s=d;
        for(int i=0;i<=n;i++)f=f.next;
        while(f!=null){f=f.next;s=s.next;}
        s.next=s.next.next;return d.next;
    }
    static ListNode mergeTwoSorted(ListNode l1,ListNode l2){
        ListNode d=new ListNode(0),c=d;
        while(l1!=null&&l2!=null){if(l1.val<=l2.val){c.next=l1;l1=l1.next;}else{c.next=l2;l2=l2.next;}c=c.next;}
        c.next=l1!=null?l1:l2;return d.next;
    }
    static ListNode addTwoNumbers(ListNode l1,ListNode l2){
        ListNode d=new ListNode(0),c=d;int carry=0;
        while(l1!=null||l2!=null||carry!=0){
            int sum=(l1!=null?l1.val:0)+(l2!=null?l2.val:0)+carry;
            carry=sum/10;c.next=new ListNode(sum%10);c=c.next;
            if(l1!=null)l1=l1.next;if(l2!=null)l2=l2.next;
        }return d.next;
    }
    static ListNode deleteDuplicates(ListNode head){
        ListNode c=head;while(c!=null&&c.next!=null){
            if(c.val==c.next.val)c.next=c.next.next;else c=c.next;}
        return head;
    }
    static ListNode of(int...vs){ListNode d=new ListNode(0),c=d;for(int v:vs){c.next=new ListNode(v);c=c.next;}return d.next;}
    static String str(ListNode h){StringBuilder sb=new StringBuilder();while(h!=null){sb.append(h.val);if(h.next!=null)sb.append("-");h=h.next;}return sb.toString();}
    public static void main(String[] args){
        System.out.println("1. removeNthFromEnd([1,2,3,4,5],2)="+str(removeNthFromEnd(of(1,2,3,4,5),2)));
        System.out.println("2. mergeTwoSorted([1,2,4],[1,3,4])="+str(mergeTwoSorted(of(1,2,4),of(1,3,4))));
        System.out.println("3. addTwoNumbers([2,4,3],[5,6,4])="+str(addTwoNumbers(of(2,4,3),of(5,6,4))));
        System.out.println("4. deleteDuplicates([1,1,2,3,3])="+str(deleteDuplicates(of(1,1,2,3,3))));
        boolean allPass=str(removeNthFromEnd(of(1,2,3,4,5),2)).equals("1-2-3-5")
            &&str(mergeTwoSorted(of(1,2,4),of(1,3,4))).equals("1-1-2-3-4-4")
            &&str(addTwoNumbers(of(2,4,3),of(5,6,4))).equals("7-0-8")
            &&str(deleteDuplicates(of(1,1,2,3,3))).equals("1-2-3");
        System.out.println("All pass: "+allPass);
    }
}
